pub struct Counter { n: u32 }

impl Counter {
    pub fn new() -> Self { Self { n: 0 } }
    pub fn tick(&mut self) { self.n += 1; }
    pub fn value(&self) -> u32 { self.n }
}

use std::collections::HashMap;
pub fn tally(words: &[&str]) -> HashMap<String, u32> {
    let mut m: HashMap<String, u32> = HashMap::new();
    for w in words {
        *m.entry(w.to_string()).or_insert(0) += 1;
    }
    m
}

pub fn collect_squares(out: &mut Vec<i32>, xs: &[i32]) {
    out.extend(xs.iter().map(|x| x * x));
}

pub fn classify(n: i32) -> &'static str {
    let abs_n = n.unsigned_abs();
    if abs_n == 0 { "zero" } else { "nonzero" }
}

pub fn first_big(xs: &[i64]) -> Option<&i64> {
    let limit: i64 = 1_000;
    xs.iter().find(|&&x| x > limit)
}

use std::sync::Mutex;
pub struct Cache { inner: Mutex<Vec<u8>> }

impl Cache {
    pub fn push_all(&self, data: &[u8]) {
        let mut g = self.inner.lock().expect("poisoned");
        g.extend_from_slice(data);
    }
}
